<script setup>
import{computed,reactive,ref}from'vue';import{Head,Link}from'@inertiajs/vue3';import axios from'axios';
const props=defineProps({participant:Object,documents:Array,templates:Array,starter:Object});const docs=ref(JSON.parse(JSON.stringify(props.documents||[])));const selectedId=ref(docs.value[0]?.id||null);const selected=computed(()=>docs.value.find(d=>d.id===selectedId.value));const typeLabels={resume:'Lebenslauf',cover_page:'Deckblatt',cover_letter:'Anschreiben'};const status=ref('');const templateSearch=ref('');const libraryOpen=ref(!docs.value.length);const filteredTemplates=computed(()=>props.templates.filter(t=>t.name.toLowerCase().includes(templateSearch.value.toLowerCase())));const newDoc=reactive({type:'resume',title:''});
async function create(){if(!newDoc.title.trim())return;const content=JSON.parse(JSON.stringify(props.starter));const r=await axios.post(route('participant-portal.career-studio.store'),{type:newDoc.type,title:newDoc.title,template_key:props.templates[0].key,content,is_default:false});docs.value.unshift(r.data.document);selectedId.value=r.data.document.id;newDoc.title=''}
async function save(){const d=selected.value;if(!d)return;status.value='Speichert …';const r=await axios.put(route('participant-portal.career-studio.update',d.id),{type:d.type,title:d.title,template_key:d.template_key,content:d.content,is_default:Boolean(d.is_default)});Object.assign(d,r.data.document);status.value='Gespeichert';setTimeout(()=>status.value='',1800)}
async function duplicate(){const r=await axios.post(route('participant-portal.career-studio.duplicate',selected.value.id));docs.value.unshift(r.data.document);selectedId.value=r.data.document.id}
async function remove(){const d=selected.value;if(!d||!confirm('Dokument wirklich löschen?'))return;await axios.delete(route('participant-portal.career-studio.destroy',d.id));docs.value=docs.value.filter(x=>x.id!==d.id);selectedId.value=docs.value[0]?.id||null}
function addEntry(){selected.value.content.entries??=[];selected.value.content.entries.push({section:'Berufserfahrung',title:'',subtitle:'',period:'',description:''})}
</script>
<template><Head title="Bewerbungsstudio"/><div class="min-h-[80vh]"><div class="mb-5 flex flex-wrap items-center justify-between gap-3"><div><h1 class="text-3xl font-bold">Professionelles Bewerbungsstudio</h1><p class="text-sm text-[var(--secondary)]">Lebensläufe, Deckblätter und Anschreiben erstellen – mit Live-Vorschau.</p></div><div class="flex flex-wrap gap-2"><button class="rounded-lg border border-[var(--border)] bg-[var(--card)] px-4 py-2" @click="libraryOpen=!libraryOpen">{{libraryOpen?'Dokumente ausblenden':'＋ Dokumente'}}</button><Link :href="route('participant-portal.jobs.index')" class="rounded-lg border border-[var(--border)] bg-[var(--card)] px-4 py-2">Zu Bewerbungen</Link><button v-if="selected" class="rounded-lg bg-[var(--buttonPrimary)] px-4 py-2 text-[var(--buttonTextPrimary)]" @click="save">Speichern</button></div></div>
<div class="grid gap-5" :class="libraryOpen?'xl:grid-cols-[240px_minmax(390px,0.8fr)_minmax(600px,1.35fr)]':'xl:grid-cols-[minmax(420px,0.72fr)_minmax(680px,1.4fr)]'"><aside v-if="libraryOpen" class="space-y-4"><section class="rounded-2xl border border-[var(--border)] bg-[var(--card)] p-4"><h2 class="font-bold">Neues Dokument</h2><select v-model="newDoc.type" class="mt-3 w-full rounded-lg border-[var(--border)] bg-[var(--inputBg)]"><option v-for="(v,k) in typeLabels" :value="k">{{v}}</option></select><input v-model="newDoc.title" class="mt-2 w-full rounded-lg border-[var(--border)] bg-[var(--inputBg)]" placeholder="z. B. Bewerbung Pflege"><button class="mt-2 w-full rounded-lg bg-[var(--buttonPrimary)] px-3 py-2 text-[var(--buttonTextPrimary)]" @click="create">Erstellen</button></section><section class="rounded-2xl border border-[var(--border)] bg-[var(--card)] p-3"><p class="px-2 pb-2 text-xs font-bold uppercase text-[var(--secondary)]">Meine Dokumente ({{docs.length}})</p><button v-for="d in docs" :key="d.id" class="mb-1 w-full rounded-xl p-3 text-left" :class="selectedId===d.id?'bg-[var(--surfaceTint)] ring-1 ring-[var(--buttonPrimary)]':'hover:bg-[var(--muted)]'" @click="selectedId=d.id;libraryOpen=false"><span class="block text-xs text-[var(--secondary)]">{{typeLabels[d.type]}}</span><b class="block truncate">{{d.title}}</b><span class="text-[10px] text-[var(--secondary)]">{{new Date(d.updated_at).toLocaleDateString('de-DE')}}</span></button></section></aside>
<section v-if="selected" class="space-y-4 rounded-2xl border border-[var(--border)] bg-[var(--card)] p-5"><div class="flex items-center justify-between"><h2 class="text-xl font-bold">Editor</h2><span class="text-sm text-emerald-600">{{status}}</span></div><label class="block text-sm font-semibold">Dokumentname<input v-model="selected.title" class="mt-1 w-full rounded-lg border-[var(--border)] bg-[var(--inputBg)]"></label><div class="grid gap-3 sm:grid-cols-2"><label class="block text-sm font-semibold">Name<input v-model="selected.content.full_name" class="mt-1 w-full rounded-lg border-[var(--border)] bg-[var(--inputBg)]"></label><label class="block text-sm font-semibold">Überschrift / Position<input v-model="selected.content.headline" class="mt-1 w-full rounded-lg border-[var(--border)] bg-[var(--inputBg)]"></label></div><label class="block text-sm font-semibold">Kontaktdaten<textarea v-model="selected.content.contact" rows="2" class="mt-1 w-full rounded-lg border-[var(--border)] bg-[var(--inputBg)]" placeholder="E-Mail · Telefon · Anschrift"></textarea></label>
<template v-if="selected.type==='resume'"><label class="block text-sm font-semibold">Kurzprofil<textarea v-model="selected.content.summary" rows="4" class="mt-1 w-full rounded-lg border-[var(--border)] bg-[var(--inputBg)]"></textarea></label><div class="flex items-center justify-between"><h3 class="font-bold">Abschnitte</h3><button class="text-sm font-semibold text-[var(--buttonPrimary)]" @click="addEntry">+ Eintrag</button></div><article v-for="(e,i) in selected.content.entries" :key="i" class="rounded-xl border border-[var(--border)] p-3"><div class="grid gap-2 sm:grid-cols-2"><input v-model="e.section" placeholder="Abschnitt" class="rounded border-[var(--border)] bg-[var(--inputBg)]"><input v-model="e.period" placeholder="Zeitraum" class="rounded border-[var(--border)] bg-[var(--inputBg)]"><input v-model="e.title" placeholder="Position / Abschluss" class="rounded border-[var(--border)] bg-[var(--inputBg)]"><input v-model="e.subtitle" placeholder="Arbeitgeber / Schule" class="rounded border-[var(--border)] bg-[var(--inputBg)]"></div><textarea v-model="e.description" rows="3" placeholder="Aufgaben, Erfolge, Kenntnisse" class="mt-2 w-full rounded border-[var(--border)] bg-[var(--inputBg)]"></textarea><button class="mt-1 text-xs text-red-600" @click="selected.content.entries.splice(i,1)">Entfernen</button></article></template>
<template v-if="selected.type==='cover_letter'"><label class="block text-sm font-semibold">Empfänger<textarea v-model="selected.content.recipient" rows="3" class="mt-1 w-full rounded-lg border-[var(--border)] bg-[var(--inputBg)]"></textarea></label><label class="block text-sm font-semibold">Betreff<input v-model="selected.content.subject" class="mt-1 w-full rounded-lg border-[var(--border)] bg-[var(--inputBg)]"></label><label class="block text-sm font-semibold">Anschreiben<textarea v-model="selected.content.body" rows="16" class="mt-1 w-full rounded-lg border-[var(--border)] bg-[var(--inputBg)]"></textarea></label></template>
<div><div class="flex justify-between"><h3 class="font-bold">Design ({{templates.length}})</h3><input v-model="templateSearch" class="w-40 rounded border-[var(--border)] bg-[var(--inputBg)] text-sm" placeholder="Suchen"></div><div class="mt-2 grid max-h-56 grid-cols-2 gap-2 overflow-y-auto"><button v-for="t in filteredTemplates" :key="t.key" class="rounded-lg border-2 p-2 text-left text-xs" :class="selected.template_key===t.key?'border-[var(--buttonPrimary)] bg-[var(--surfaceTint)]':'border-[var(--border)]'" @click="selected.template_key=t.key"><span class="mb-1 block h-2 rounded" :style="{background:t.color}"></span>{{t.name}}</button></div></div><div class="flex flex-wrap gap-2 border-t border-[var(--border)] pt-4"><button class="rounded border border-[var(--border)] px-3 py-2 text-sm" @click="duplicate">Duplizieren</button><a target="_blank" :href="route('participant-portal.career-studio.preview',selected.id)" class="rounded border border-[var(--border)] px-3 py-2 text-sm">PDF-Vorschau</a><a :href="route('participant-portal.career-studio.download',selected.id)" class="rounded border border-[var(--border)] px-3 py-2 text-sm">PDF</a><button class="ml-auto text-sm text-red-600" @click="remove">Löschen</button></div></section>
<section v-if="selected" class="sticky top-5 h-fit"><p class="mb-2 text-xs font-bold uppercase text-[var(--secondary)]">Live-Vorschau</p><div class="aspect-[1/1.414] overflow-y-auto bg-white p-[7%] text-zinc-800 shadow-2xl" :style="{fontFamily:selected.template_key.includes('serif')?'Georgia,serif':'Arial,sans-serif',borderTop:`7px solid ${templates.find(t=>t.key===selected.template_key)?.color}`}" ><template v-if="selected.type==='cover_page'"><div class="flex min-h-full flex-col items-center justify-center text-center"><p class="tracking-[.3em] text-zinc-500">BEWERBUNG</p><h1 class="mt-5 text-4xl font-bold" :style="{color:templates.find(t=>t.key===selected.template_key)?.color}">{{selected.content.full_name}}</h1><p class="mt-5 text-xl">{{selected.content.headline}}</p><p class="mt-12 whitespace-pre-line text-sm text-zinc-500">{{selected.content.contact}}</p></div></template><template v-else-if="selected.type==='cover_letter'"><h1 class="text-2xl font-bold">{{selected.content.full_name}}</h1><p class="whitespace-pre-line text-xs text-zinc-500">{{selected.content.contact}}</p><p class="mt-10 whitespace-pre-line text-sm">{{selected.content.recipient}}</p><h2 class="mt-8 font-bold">{{selected.content.subject}}</h2><p class="mt-4 whitespace-pre-line text-sm leading-6">{{selected.content.body}}</p></template><template v-else><h1 class="text-3xl font-bold" :style="{color:templates.find(t=>t.key===selected.template_key)?.color}">{{selected.content.full_name}}</h1><p class="text-lg">{{selected.content.headline}}</p><p class="text-xs text-zinc-500">{{selected.content.contact}}</p><h2 class="mt-6 border-b font-bold uppercase">Profil</h2><p class="mt-2 text-sm">{{selected.content.summary}}</p><template v-for="(group,section) in Object.groupBy(selected.content.entries||[],e=>e.section||'Weitere Angaben')"><h2 class="mt-5 border-b font-bold uppercase">{{section}}</h2><article v-for="e in group" class="mt-3"><div class="flex justify-between"><b>{{e.title}}</b><span class="text-xs">{{e.period}}</span></div><p class="text-xs text-zinc-500">{{e.subtitle}}</p><p class="mt-1 whitespace-pre-line text-sm">{{e.description}}</p></article></template></template></div></section><div v-else class="col-span-2 rounded-2xl border-2 border-dashed border-[var(--border)] p-12 text-center text-[var(--secondary)]">Erstellen Sie links Ihr erstes Bewerbungsdokument.</div></div></div></template>
